import{_ as e,o as s,c as n,d as a}from"./app-51f2a91d.js";const o="/blog/assets/image/http-request.png",t="/blog/assets/image/http-response.png",r={},l=a(`<h1 id="http-报文结构与状态码" tabindex="-1"><a class="header-anchor" href="#http-报文结构与状态码" aria-hidden="true">#</a> HTTP 报文结构与状态码</h1><blockquote><p><strong>引言</strong> 在上一篇《万维网基石之HTTP》中，我们了解了 HTTP 是客户端与服务器之间的“沟通语言”。 那么，这门语言到底长什么样？当我们调用 <code>fetch</code> 或 <code>axios</code> 发送一个请求时，网络底层到底传输了什么样的数据格式？如果出错了，那些神奇的数字（404, 502）到底在暗示什么？ 今天，我们就来做一次“网络外科手术”，彻底解剖 HTTP 报文结构，并盘点那些前端每天都要打交道的状态码。</p></blockquote><h2 id="一、-http-报文-网络世界里的-信封与信件" tabindex="-1"><a class="header-anchor" href="#一、-http-报文-网络世界里的-信封与信件" aria-hidden="true">#</a> 一、 HTTP 报文：网络世界里的“信封与信件”</h2><p>HTTP 协议的通信过程，本质上就是客户端和服务端在互相传递“报文（Message）”。</p><p>为了方便理解，我们可以把 HTTP 报文想象成一封我们在现实生活中寄出的<strong>快递信件</strong>：</p><ul><li><strong>起始行（信封正面第一行）</strong>：写着这封信是寄给谁的、寄加急还是平邮。</li><li><strong>首部字段 Headers（信封上的其他信息）</strong>：写着寄件人是谁、信件有多重、用什么语言写的。</li><li><strong>空行（信封的封口）</strong>：一个没有任何内容的空行，用来告诉对方“信封上的信息写完了，下面是信件正文”。</li><li><strong>报文主体 Body（信封里的信纸/物品）</strong>：你真正要传递的内容，比如一段 JSON 数据、一张图片。</li></ul><p>HTTP 报文分为两类：<strong>请求报文（Request）</strong> 和 <strong>响应报文（Response）</strong>。它们的结构非常相似，但细节略有不同。</p><h3 id="_1-客户端发出的-请求报文-request-message" tabindex="-1"><a class="header-anchor" href="#_1-客户端发出的-请求报文-request-message" aria-hidden="true">#</a> 1. 客户端发出的：请求报文 (Request Message)</h3><p>当你在浏览器地址栏输入网址按回车，或者用 AJAX 发起 POST 请求时，浏览器会帮你拼装出这样一个纯文本格式的数据包：</p><div class="language-http line-numbers-mode" data-ext="http"><pre class="language-http"><code><span class="token request-line"><span class="token method property">POST</span> <span class="token request-target url">/api/login</span> <span class="token http-version property">HTTP/1.1</span></span>          &lt;-- [起始行]
<span class="token header"><span class="token header-name keyword">Host</span><span class="token punctuation">:</span> <span class="token header-value">www.example.com             &lt;-- [首部 Headers 开始]</span></span>
<span class="token header"><span class="token header-name keyword">User-Agent</span><span class="token punctuation">:</span> <span class="token header-value">Mozilla/5.0 ...</span></span>
<span class="token header"><span class="token header-name keyword">Content-Type</span><span class="token punctuation">:</span> <span class="token header-value">application/json</span></span>
<span class="token header"><span class="token header-name keyword">Content-Length</span><span class="token punctuation">:</span> <span class="token header-value">36                &lt;-- [首部 Headers 结束]
                                  &lt;-- [空行 (CRLF)]</span></span>
{&quot;username&quot;:&quot;admin&quot;,&quot;pwd&quot;:&quot;123&quot;}  &lt;-- [报文主体 Body]
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>手术刀解剖：</strong></p><ul><li><strong>起始行（Request Line）</strong>：由三部分组成，空格隔开。 <ul><li><strong>方法 (Method)</strong>：动词。比如这里的 <code>POST</code>，或者 <code>GET</code>, <code>PUT</code>, <code>DELETE</code>。告诉服务器你想做什么动作。</li><li><strong>请求目标 (URI/URL)</strong>：名词。比如这里的 <code>/api/login</code>，告诉服务器你要操作哪个资源。</li><li><strong>HTTP 版本号</strong>：比如这里的 <code>HTTP/1.1</code>，告诉服务器我懂哪门语言。</li></ul></li><li><strong>首部字段（Headers）</strong>：由 <code>Key: Value</code> 的键值对组成。它是 HTTP 协议最灵活、最核心的部分（我们在下一篇会专门讲缓存和鉴权相关的 Headers）。</li><li><strong>空行</strong>：极其重要！它是解析 HTTP 报文的界限，标志着 Headers 的结束和 Body 的开始。</li><li><strong>报文主体（Body）</strong>：你要传给后端的数据。<strong>注意：GET 请求通常没有 Body，只有 POST/PUT 等请求才有。</strong></li></ul><h3 id="_2-服务器返回的-响应报文-response-message" tabindex="-1"><a class="header-anchor" href="#_2-服务器返回的-响应报文-response-message" aria-hidden="true">#</a> 2. 服务器返回的：响应报文 (Response Message)</h3><p>后端处理完你的请求后，会按同样的格式给你回一封信：</p><div class="language-http line-numbers-mode" data-ext="http"><pre class="language-http"><code><span class="token response-status"><span class="token http-version property">HTTP/1.1</span> <span class="token status-code number">200</span> <span class="token reason-phrase string">OK                   &lt;-- [起始行]</span></span>
<span class="token header"><span class="token header-name keyword">Date</span><span class="token punctuation">:</span> <span class="token header-value">Tue, 24 Oct 2023 10:00:00   &lt;-- [首部 Headers 开始]</span></span>
<span class="token header"><span class="token header-name keyword">Server</span><span class="token punctuation">:</span> <span class="token header-value">Nginx/1.22</span></span>
<span class="token header"><span class="token header-name keyword">Content-Type</span><span class="token punctuation">:</span> <span class="token header-value">application/json</span></span>
<span class="token header"><span class="token header-name keyword">Set-Cookie</span><span class="token punctuation">:</span> <span class="token header-value">token=abcde; HttpOnly &lt;-- [首部 Headers 结束]
                                  &lt;-- [空行]</span></span>
{&quot;code&quot;:0, &quot;msg&quot;:&quot;登录成功&quot;}       &lt;-- [报文主体 Body]
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>手术刀解剖：</strong> 响应报文的区别主要在<strong>第一行（状态行 Status Line）</strong>：</p><ul><li><strong>HTTP 版本号</strong>：<code>HTTP/1.1</code>。</li><li><strong>状态码 (Status Code)</strong>：数字。比如这里的 <code>200</code>，它是核心！告诉前端这次请求的结果是成功还是失败。</li><li><strong>状态原因短语 (Reason Phrase)</strong>：文本。比如这里的 <code>OK</code>，只是给人看的，机器只认前面的数字。</li></ul><hr><h2 id="二、-前端背锅-甩锅指南-http-状态码全解析" tabindex="-1"><a class="header-anchor" href="#二、-前端背锅-甩锅指南-http-状态码全解析" aria-hidden="true">#</a> 二、 前端背锅/甩锅指南：HTTP 状态码全解析</h2><p>在日常开发中，当我们点开 Chrome DevTools 的 Network 面板看到满屏的红色报错时，第一时间就要看<strong>状态码</strong>。</p><p>状态码由 3 位数字组成，分为 5 大类。<strong>记住它们的分类，你能瞬间判断出这个 Bug 到底是前端的锅，还是后端的锅。</strong></p><h3 id="_1-【1xx】信息性状态码-看戏就好" tabindex="-1"><a class="header-anchor" href="#_1-【1xx】信息性状态码-看戏就好" aria-hidden="true">#</a> 1. 【1xx】信息性状态码：看戏就好</h3><ul><li><strong>含义</strong>：服务器正在处理请求，请客户端稍安勿躁。</li><li><strong>前端感知</strong>：日常开发极少直接接触。</li><li><em>代表作</em>： <ul><li><code>101 Switching Protocols</code>：前端发起 WebSocket 连接时，服务器同意把 HTTP 协议升级为 WebSocket 协议，就会返回 101。</li></ul></li></ul><h3 id="_2-【2xx】成功状态码-皆大欢喜" tabindex="-1"><a class="header-anchor" href="#_2-【2xx】成功状态码-皆大欢喜" aria-hidden="true">#</a> 2. 【2xx】成功状态码：皆大欢喜</h3><ul><li><strong>含义</strong>：请求已被服务器成功接收、理解并接受。</li><li><em>代表作</em>： <ul><li><code>200 OK</code>：最常见的成功状态码，GET 拿到了数据，POST 提交成功。</li><li><code>201 Created</code>：通常用于 POST/PUT，表示服务器成功创建了新的资源（比如新建了一个用户）。</li><li><code>204 No Content</code>：请求成功了，但服务器没有什么数据要返回给你（Body 为空）。<strong>前端注意</strong>：CORS 跨域的预检请求（OPTIONS）成功时，通常返回的就是 204。</li></ul></li></ul><h3 id="_3-【3xx】重定向状态码-查缓存与跳转" tabindex="-1"><a class="header-anchor" href="#_3-【3xx】重定向状态码-查缓存与跳转" aria-hidden="true">#</a> 3. 【3xx】重定向状态码：查缓存与跳转</h3><ul><li><strong>含义</strong>：前端你需要进一步操作（通常是去另一个地址找，或者直接读本地缓存）才能完成请求。</li><li><em>代表作</em>： <ul><li><code>301 Moved Permanently</code>（永久重定向）：网站换域名了。<strong>前端大坑</strong>：浏览器会死死记住 301 缓存，下次你访问旧地址，浏览器连网都不上，直接内部跳转。</li><li><code>302 Found</code>（临时重定向）：没登录想进后台，被临时踢到了 <code>/login</code> 登录页。</li><li>🔥 <code>304 Not Modified</code>（未修改）：<strong>前端性能优化核心！</strong> 协商缓存命中。服务器告诉你：“文件没改过，别下载了，直接用你本地硬盘里的旧文件吧”。（它的 Body 也是空的，极大地节省了带宽）。</li></ul></li></ul><h3 id="_4-【4xx】客户端错误状态码-前端赶紧查代码" tabindex="-1"><a class="header-anchor" href="#_4-【4xx】客户端错误状态码-前端赶紧查代码" aria-hidden="true">#</a> 4. 【4xx】客户端错误状态码：前端赶紧查代码！</h3><ul><li><strong>含义</strong>：<strong>前端的锅！</strong> 你发送的请求有问题（参数拼错、没带 Token、格式不对），服务器拒绝处理。</li><li><em>代表作</em>： <ul><li><code>400 Bad Request</code>：参数校验失败。比如后端要数字，你传了字符串。</li><li><code>401 Unauthorized</code>：<strong>身份验证失败</strong>。你没登录，或者 Token 过期了。前端通常要在 axios 拦截器里捕获 401，然后清除本地 Token 并跳回登录页。</li><li><code>403 Forbidden</code>：<strong>权限不足</strong>。你登录了，但我知道你是谁，你只是普通用户，不准调管理员接口。</li><li><code>404 Not Found</code>：<strong>找不到资源</strong>。你要么 URL 拼写错误，要么后端老哥还没把接口发上线。</li><li><code>405 Method Not Allowed</code>：<strong>方法用错了</strong>。后端写的是 <code>app.post(&#39;/hello&#39;)</code>，你前端偏用 <code>axios.get(&#39;/hello&#39;)</code> 请求，直接报错。</li></ul></li></ul><h3 id="_5-【5xx】服务器错误状态码-立刻截图找后端" tabindex="-1"><a class="header-anchor" href="#_5-【5xx】服务器错误状态码-立刻截图找后端" aria-hidden="true">#</a> 5. 【5xx】服务器错误状态码：立刻截图找后端！</h3><ul><li><strong>含义</strong>：<strong>后端的锅！</strong> 前端的请求完全合法完美，但后端代码写崩了，或者服务器挂了。</li><li><em>代表作</em>： <ul><li><code>500 Internal Server Error</code>：最典型的后端报错。比如后端代码抛了“空指针异常”，或者 SQL 语句写错了。直接把截图扔给后端排查日志。</li><li><code>502 Bad Gateway</code>（网关错误）：你请求打到了 Nginx（网关），但背后的真实服务器（如 Node.js 或 Java 进程）挂掉了没启动。Nginx 拿不到数据，只能给你退回 502。</li><li><code>503 Service Unavailable</code>：服务器超载了（双十一被挤爆了），或者正在停机维护。</li><li><code>504 Gateway Timeout</code>：后端处理得太慢了（比如查数据库卡了 60 秒），Nginx 等得不耐烦了，直接切断连接告诉你超时。</li></ul></li></ul><hr><h2 id="三、http-请求与响应图示" tabindex="-1"><a class="header-anchor" href="#三、http-请求与响应图示" aria-hidden="true">#</a> 三、http 请求与响应图示</h2><figure><img src="`+o+'" alt="http request" tabindex="0" loading="lazy"><figcaption>http request</figcaption></figure><figure><img src="'+t+'" alt="http response" tabindex="0" loading="lazy"><figcaption>http response</figcaption></figure><blockquote><p><strong>结语</strong> HTTP 报文看似复杂，其实只是一封格式严格的“纯文本信件”。当我们弄懂了这封信的结构，并熟记了 4xx 和 5xx 状态码的区别，以后在面对控制台里红彤彤的报错时，我们就能做到胸有成竹、精准定位。</p></blockquote><hr>',37),i=[l];function d(c,p){return s(),n("div",null,i)}const h=e(r,[["render",d],["__file","01.html.vue"]]);export{h as default};
